schema Kotelok2 { version: 1, namespace: "kotelok2" }
use "./players" { Player }
record GameRoom @scope(name: "room") @sync(qos: RELIABLE) {
  id: ID!
  players: [Player!]!
}
action CreateRoom { output: ID! }
action JoinRoom { scope: "room", input: { name: String!, clientId: String! }, output: Player! }
action LeaveRoom { scope: "room", input: { clientId: String! } }

schema Kotelok2 { version: 1, namespace: "kotelok2" }
use "./core" { ClientId }
record Player {
  id: ID!
  name: String
  clientId: ClientId!
  status: String
}
